import{_ as e,c as a,a as s,o as t}from"./app-CddT6UHG.js";const o={};function c(i,n){return t(),a("div",null,n[0]||(n[0]=[s(`<h1 id="context-cache" tabindex="-1"><a class="header-anchor" href="#context-cache"><span>Context Cache</span></a></h1><p>In this section, you will learn how to use the context cache to speed up your application.</p><p>The context cache is a per-request, in-memory cache that lives on the <code>fluxaorm.Context</code> object. It is <strong>enabled by default</strong> with a TTL of <strong>1 second</strong>. When an entity is loaded via <code>GetByID</code> or <code>GetByIDs</code>, it is automatically stored in the context cache. Subsequent calls to <code>GetByID</code> or <code>GetByIDs</code> for the same entity within the TTL window will return the cached copy without hitting MySQL or Redis.</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> fluxaorm <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// executes query to DB/Redis</span></span>
<span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>  <span class="token comment">// served from context cache (no DB/Redis query)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>The context cache is only populated by <code>GetByID</code> and <code>GetByIDs</code>. Search methods (<code>Search</code>, <code>SearchOne</code>, <code>SearchIDs</code>, etc.) do <strong>not</strong> read from or write to the context cache.</p></div><h2 id="ttl-and-expiration" tabindex="-1"><a class="header-anchor" href="#ttl-and-expiration"><span>TTL and Expiration</span></a></h2><p>The default TTL is 1 second (1000 milliseconds). When the TTL expires, the <strong>entire</strong> context cache map is cleared on the next read attempt. This means all cached entities across all entity types are removed at once, not on a per-entry basis.</p><p>This design makes the context cache ideal for short-lived scopes such as a single HTTP request. For long-running processes, either disable the context cache or use a short TTL and create a fresh context for each unit of work.</p><h2 id="customizing-the-ttl" tabindex="-1"><a class="header-anchor" href="#customizing-the-ttl"><span>Customizing the TTL</span></a></h2><p>You can change the TTL using <code>SetContextCacheTTL()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetContextCacheTTL</span><span class="token punctuation">(</span><span class="token number">5</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span> <span class="token comment">// cache entries are valid for 5 seconds</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>Set the TTL before any <code>GetByID</code> / <code>GetByIDs</code> calls to ensure it takes effect from the start.</p><h2 id="disabling-the-context-cache" tabindex="-1"><a class="header-anchor" href="#disabling-the-context-cache"><span>Disabling the Context Cache</span></a></h2><p>You can disable the context cache entirely by calling <code>DisableContextCache()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">DisableContextCache</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// always executes query to DB/Redis</span></span>
<span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>  <span class="token comment">// always executes query to DB/Redis</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Once disabled, the context cache cannot be re-enabled on the same context. If you need caching again, create a new context.</p><h2 id="how-it-works-internally" tabindex="-1"><a class="header-anchor" href="#how-it-works-internally"><span>How It Works Internally</span></a></h2><p>The context cache uses two low-level methods on the <code>Context</code> interface that are called by the generated entity code:</p><ul><li><code>GetFromContextCache(cacheIndex uint64, id uint64) Entity</code> -- looks up an entity in the cache by its type index and ID. Returns <code>nil</code> if not found or if the cache is disabled/expired.</li><li><code>SetInContextCache(cacheIndex uint64, id uint64, entity Entity)</code> -- stores an entity in the cache. Does nothing if the cache is disabled.</li></ul><p>The <code>cacheIndex</code> is a unique identifier for each entity type, generated at code-generation time. You should not need to call these methods directly -- they are used automatically by the generated <code>GetByID</code> and <code>GetByIDs</code> functions.</p><h2 id="interaction-with-entity-tracking" tabindex="-1"><a class="header-anchor" href="#interaction-with-entity-tracking"><span>Interaction with Entity Tracking</span></a></h2><p>When an entity is modified and tracked for flushing (via <code>ctx.Track()</code>), it is <strong>removed</strong> from the context cache. This prevents stale reads of an entity that has pending changes. After <code>ctx.Flush()</code> completes, subsequent <code>GetByID</code> calls will fetch the updated entity from the database and re-populate the context cache.</p>`,22)]))}const l=e(o,[["render",c]]),u=JSON.parse('{"path":"/guide/context_cache.html","title":"Context Cache","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772273114000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":4,"url":"https://github.com/lukaszlato"},{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":1}],"changelog":[{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"2999eaa1d9039b9b2196f72bc8646d1b5b21e9b6","time":1761818175000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"8e6b703eb384e27f9252e14535c732736a9a123b","time":1761652891000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"c0402f53ec17e8f0ec0241bb904f0920cb9f0a0e","time":1761138653000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"}]},"filePathRelative":"guide/context_cache.md"}');export{l as comp,u as data};
